"""Emission compliance tests for cli_observability_and_fix (auto-generated by pact)."""

from cli_observability_and_fix.cli_observability_and_fix import CliObservabilityAndFix


class TestEmissionCompliance:
    """Verify cli_observability_and_fix emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_derive_validate_mode_emits_events(self):
        """Method derive_validate_mode emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = CliObservabilityAndFix(event_handler=handler)
        try:
            obj.derive_validate_mode()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for derive_validate_mode'
        assert len(completed) >= 1, 'No completed/error event for derive_validate_mode'
        assert invoked[0].get("pact_key") == "PACT:cli_observability_and_fix:derive_validate_mode"
        assert isinstance(invoked[0].get("input_classification"), list)

