    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = CliObservabilityAndFix(event_handler=handler)
        try:
            obj.derive_validate_mode()
        except (TypeError, Exception):
            pass
        try:
            obj.fix_policy()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_validate()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_enable()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_status()
        except (TypeError, Exception):
            pass
        try:
            obj.render_fix_diff()
        except (TypeError, Exception):
            pass
        try:
            obj.render_enforcement_state()
        except (TypeError, Exception):
            pass
        try:
            obj.build_enable_result()
        except (TypeError, Exception):
            pass
        try:
            obj.query_enforcement_state()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:cli_observability_and_fix:"), f"Bad pact_key: {key}"

